/* selectTplnhdList */ SELECT
TPL.COMPKEY , TPL.VHPLNKY , TPL.WAREKEY , TPL.VEHICKY , TPL.DOCCATE , TPL.DOCTYPE , TPL.POSTDAT , TPL.VHPDATE , TPL.VHPTIME , TPL.USERACT
, fn_sy_usernam(TPL.COMPKEY, TPL.USERACT) as USERNAM
, TPL.STPITDT , TPL.STPITTM , TPL.PLNSTAT , TPL.TRNMEMO , TPL.EMERSCD , TPL.EMERDNM , TPL.PCARSCD , TPL.PCARSNM , TPL.PCADATE , TPL.PCATIME , TPL.PCAUSER , TPL.TRFINDT , TPL.TRFINTM , TPL.PBILLYN , TPL.PBILPAY , TPL.SHTRTKY , TPL.TRAREKY , fn_com_todate(TPL.CREDATE) as CREDATE , fn_com_totime(TPL.CRETIME) as CRETIME , fn_sy_usernam(TPL.COMPKEY, TPL.CREUSER) as CREUSER , fn_com_todate(TPL.LMODATE) as LMODATE , fn_com_totime(TPL.LMOTIME) as LMOTIME , fn_sy_usernam(TPL.COMPKEY, TPL.LMOUSER) as LMOUSER
, MWA.WHNAMLC, MWA.WHNAMKO, MWA.WHNAMEN
, SH.SHTRTNM , TR.TRARENM
FROM TPLNHD TPL
INNER JOIN MWARMA MWA ON TPL.COMPKEY = MWA.COMPKEY AND TPL.WAREKEY = MWA.WAREKEY AND MWA.WHUSEYN = 'Y'
LEFT JOIN TSHRHD SH ON TPL.COMPKEY = SH.COMPKEY AND TPL.WAREKEY = SH.WAREKEY AND TPL.SHTRTKY = SH.SHTRTKY AND SH.TSUSEYN = 'Y'
LEFT JOIN TAREHD TR ON TPL.COMPKEY = TR.COMPKEY AND TPL.WAREKEY = TR.WAREKEY AND TPL.TRAREKY = TR.TRAREKY AND TR.TRUSEYN = 'Y'
WHERE 1=1 AND TPL.COMPKEY = #{userData.compkey}
AND vhplnky = #{vhplnky}
AND warekey = #{warekey}
AND vehicky = #{vehicky}
AND (vehicky = #{vehickyornot} OR vehicky is NULL OR vehicky = '' OR vehicky = ' ')
AND VEHICKY in (
#{item}
)
AND TPL.SHTRTKY = #{shtrtky}
AND TPL.SHTRTKY in (
#{item}
)
AND (TPL.SHTRTKY in (
#{item}
) OR TPL.SHTRTKY is NULL OR TPL.SHTRTKY = '' OR TPL.SHTRTKY = ' ' )
AND (useract = #{useractornot} OR useract is NULL OR useract = '' OR useract = ' ')
AND doccate = #{doccate}
AND doctype = #{doctype}
AND shtrtky = #{shtrtky}
AND vhpdate LIKE CONCAT('%', #{vhpdate}, '%')
AND VHPDATE LIKE date_format(now(), 'YYYYMMDD')
AND VHPDATE > date_format(now(), 'YYYYMMDD')
AND VHPDATE < date_format(now(), 'YYYYMMDD')
AND VHPDATE <= date_format(now(), 'YYYYMMDD')
AND VHPDATE LIKE date_format(now(), 'YYYYMMDD')
AND VHPDATE > date_format(now(), 'YYYYMMDD')
AND VHPDATE < date_format(now(), 'YYYYMMDD')
AND VHPDATE <= date_format(now(), 'YYYYMMDD')
AND VHPDATE >= #{startdate}
AND VHPDATE <= #{enddate}
AND PLNSTAT in ('PLAN', 'LOADING', 'START', 'UNLOADING')
AND PLNSTAT in ('PLAN')
AND PLNSTAT in ('FINISH')
AND PLNSTAT in ('CANCEL')
ORDER BY FIELD(PLNSTAT, 'PLAN', 'LOADING', 'START', 'UNLOADING', 'FINISH', 'CANCEL'), VHPLNKY DESC
LIMIT offsetnumber limitnumber

/* selectTplnitList */ SELECT /* TPIT.* */ TPIT.COMPKEY , TPIT.VHPLNKY , TPIT.VHPLNIT , TPIT.SHTRPTY , TPIT.WAREKEY , TPIT.DESTORD , TPIT.CUSTKEY , TPIT.DESTKEY , TPIT.SHTRSTS , TPIT.OWNERKY , TPIT.SKUMKEY , TPIT.SKUDESC , TPIT.SKUSKEY , TPIT.SOITQTY , TPIT.TRITQTY , TPIT.SUOMKEY , TPIT.TRUNTYP , TPIT.TRUNPID , TPIT.SAATN01 , TPIT.SAATN02 , TPIT.SAATN03 , TPIT.SAATN04 , TPIT.SAATN05 , TPIT.SAATC01 , TPIT.SAATC02 , TPIT.SAATC03 , TPIT.SAATC04 , TPIT.SAATC05 , TPIT.SAATC06
, MIN(TPIT.SAATC10) as SAATC10MIN , MAX(TPIT.SAATC10) as SAATC10MAX , MIN(TPIT.SAATC05) as SAATC05MIN
, TPIT.SAATC07 , TPIT.SAATC08 , TPIT.SAATC09 , TPIT.SAATC10
, TPIT.REPITDT , TPIT.REPITTM , TPIT.RSNCODE , TPIT.RSNREMK , TPIT.COPODKY , TPIT.COPODIT , TPIT.COOUTKY , TPIT.COOUTIT , TPIT.OERETKY , TPIT.OERETIT , TPIT.EOASNKY , TPIT.EOASNIT , TPIT.RCVDCKY , TPIT.RCVDCIT , TPIT.REFSODC , TPIT.REFSOIT , TPIT.REFDNDC , TPIT.REFDNIT , TPIT.REFSDDC , TPIT.REFSDIT , fn_com_todate(TPIT.CREDATE) as CREDATE , fn_com_totime(TPIT.CRETIME) as CRETIME , fn_sy_usernam(COMPKEY, TPIT.CREUSER) as CREUSER , fn_com_todate(TPIT.LMODATE) as LMODATE , fn_com_totime(TPIT.LMOTIME) as LMOTIME , fn_sy_usernam(COMPKEY, TPIT.LMOUSER) as LMOUSER
, DST.DENAMLC, DST.DENAMKO, DST.DENAMEN
, MWA.WANAMLC, MWA.WHNAMKO, MWA.WANAMEN , PTN.PTNAMLC, PTN.PTADDR1, PTN.PTADDR2, PTN.PTADDR3
FROM TPLNIT TPIT
INNER JOIN MDESMA DST ON TPIT.COMPKEY = DST.COMPKEY AND TPIT.CUSTKEY = DST.PTNRKEY AND TPIT.DESTKEY = DST.DESTKEY AND DST.DEUSEYN= 'Y'
INNER JOIN MWARMA MWA ON TPIT.COMPKEY = MWA.COMPKEY AND TPIT.WAREKEY = MWA.WAREKEY AND MWA.WHUSEYN = 'Y'
LEFT OUTER JOIN ( SELECT PTN.PTNRKEY, PTN.PTNAMLC, PTN.PTADDR1, PTN.PTADDR2, PTN.PTADDR3, PTN.COMPKEY as COMPKEY4 FROM MPTNMA PTN ) PTN ON TPIT.COMPKEY = PTN.COMPKEY4 AND TPIT.CUSTKEY = PTN.PTNRKEY
WHERE 1=1 AND COMPKEY = #{userData.compkey}
AND vhplnky = #{vhplnky}
AND vhplnit = #{vhplnit}
AND warekey = #{warekey}
AND shtrpty = #{shtrpty}
AND destord = #{destord}
AND custkey = #{custkey}
AND destkey = #{destkey}
AND shtrsts = #{shtrsts}
AND ownerky = #{ownerky}
GROUP BY TPIT.SAATC06
ORDER BY FIELD(SHTRPTY, 'START', 'ARRIVAL', 'END'), VHPLNIT ASC , DESTKEY ASC , DESTORD ASC , SAATC10 ASC

