      IT.SHTRSTS = 'LOADING'
  , IT.REPITDT = to_char(now(), 'YYYYMMDD')
  , IT.REPITTM = to_char(now(), 'hh24miss')
    , IT.LMODATE = to_char(now(), 'YYYYMMDD')
    , IT.LMOTIME = to_char(now(), 'hh24miss')
    , IT.LMOUSER = #{userData.useract}
