UPDATE OCOSAL T,
  inner join  
  (
    SELECT COMPKEY, COOUTKY, SAATC06
      FROM TPLNIT
      WHERE COMPKEY = #{userData.compkey}
        AND VHPLNKY = #{vhplnky}
        AND VHPLNIT IN (

            #{_vhplnit}

        )
  ) S

  ON  T.COMPKEY = S.COMPKEY
  AND T.SAATC06 = S.SAATC06
  AND T.COOUTKY = S.COOUTKY
SET T.TRNSTAT = 'UNLOADING'
WHERE 1=1

update OCOPUR OP
  set

    OP.PURSTAT = 'LOADING'
  where 1=1
    AND OP.COPODKY = (
      SELECT IT.COPODKY
        FROM TPLNIT IT
        WHERE 1=1
          AND IT.COMPKEY = #{userData.compkey}
          AND IT.VHPLNKY = #{vhplnky}
          AND IT.VHPLNIT = #{_vhplnit}
    )
    AND OP.COPODIT = (
      SELECT IT.COPODIT
        FROM TPLNIT IT
        WHERE 1=1
          AND IT.COMPKEY = #{userData.compkey}
          AND IT.VHPLNKY = #{vhplnky}
          AND IT.VHPLNIT = #{_vhplnit}
    )

