SELECT
COMPKEY , COOUTKY , COOUTIT , DOCCATE , DOCTYPE , POSTDAT , SALDATE , SALTIME , CUSTKEY , SALMEMO , SALRQDT , SALRQTM
, DESTKEY , OWNERKY , SKUMKEY , SKUDESC , SKUSKEY , SOITQTY , RGITQTY , SUOMKEY , DCTCTYP , RSNCODE , RSNDESC
, INBSTAT , OUBSTAT , TRNSTAT
, ORDGR01 , ORDGR02 , ORDGR03 , SAATN01 , SAATN02 , SAATN03 , SAATN04 , SAATN05 , SAATC01 , SAATC02 , SAATC03 , SAATC04 , SAATC05 , SAATC06
, MIN(SAATC10) as SAATC10MIN , MAX(SAATC10) as SAATC10MAX , MIN(SAATC05) as SAATC05MIN
, SAATC07 , SAATC08 , SAATC09 , SAATC10 , SAATC11 , SAATC12
, CLOSLYN , CLODATE , CLOTIME , CLOUSER
, CREDATE , CRETIME , CREUSER , LMODATE , LMOTIME , LMOUSER
FROM OCOSAL OS
FORCE INDEX(IX_OCOSAL04)
WHERE 1=1
and COMPKEY = #{userData.compkey}
AND towarky = #{towarky}
AND POSTDAT >= #{postdat_from}
AND POSTDAT in (
#{item}
)
AND salstat = #{salstat}
AND trnstat = #{trnstat}
and DOCTYPE in (
#{item}
)
AND DESTKEY = #{destkey}
GROUP BY SAATC06 ORDER BY SAATC11 LIMIT #{destlimit}
OFFSET #{offset}

SELECT COMPKEY  
  , MIN(COOUTKY) as COOUTKY
  , MIN(COOUTIT) as COOUTIT
  , POSTDAT 
  , CUSTKEY
  , DESTKEY



  , MIN(SAATC05) as SAATC05MIN
  , SAATC06  

  , SAATC08
  , MIN(SAATC10) as SAATC10MIN, MAX(SAATC10) as SAATC10MAX

  , SAATC13 
FROM OCOSAL OS 
  FORCE INDEX(IX_OCOSAL04)  
  WHERE 1=1 
      and COMPKEY = #{userData.compkey}


      AND towarky = #{towarky}


      AND POSTDAT   >=  #{postdat_from}


      AND POSTDAT in (

          #{item}

      )


      AND salstat = #{salstat}


      AND trnstat = #{trnstat}



      and DOCTYPE in (

          #{item}

      )



      AND DESTKEY = #{destkey}



      AND SAATC13 = #{saatc13}


      AND SAATC13 != #{saatc13not}

  GROUP BY COMPKEY  
      , POSTDAT 
      , CUSTKEY
      , DESTKEY    
      , SAATC06  
      , SAATC08 
      , SAATC13

  ORDER BY SAATC11  

  LIMIT #{destlimit}

SELECT
COMPKEY , COPODKY , COPODIT , DOCCATE , DOCTYPE , PURSTAT , PURDATE , PURTIME , CUSTKEY , DESTKEY , VENDKEY , OWNERKY , SKUSKEY , SKUMKEY , SKUDESC , POITQTY , PUOMKEY , RCHSQTY , PODMEMO , PODELYN , RCVWHKY , REQDATE , REQTIME , REQMEMO , COOUTKY , COOUTIT , VNDCFYN , VNDCFDT , VNDCFTM , DCTCTYP , CREDATE , CRETIME , CREUSER
FROM OCOPUR OP WHERE 1=1 and COMPKEY = #{userData.compkey} and DOCTYPE = #{doctype}

