select BH.BTHDCKY
  from BTGTHD BH
    inner join BTGTIT BI
    on BH.COMPKEY = BI.COMPKEY 
    and BH.WAREKEY = BI.WAREKEY 
    and BH.BTHDCKY = BI.BTHDCKY 
where BH.COMPKEY = #{userData.compkey}
  and BH.WAREKEY = #{warekey}
  and BI.VEHICKY = #{vehicky}
  and BH.BTHYYMM = #{bthyymm}
GROUP BY BTHDCKY
